var CONVERSATIONS_NL_EN = [
{ title: "Koffie bestellen in een café", scene: "Je bent in een klein café in Londen vlak bij Covent Garden. Het is ochtend en je wilt koffie bestellen met iets kleins erbij.", lines: [{ who: "them", en: "Good morning, what can I get for you?", nl: "Goedemorgen, wat kan ik voor u halen?" }, { who: "you", en: "Good morning, can I have a coffee, please?", nl: "Goedemorgen, mag ik een koffie, alstublieft?" }, { who: "them", en: "Of course, would you like milk or sugar?", nl: "Natuurlijk, wilt u melk of suiker?" }, { who: "you", en: "With milk, please, but no sugar.", nl: "Met melk, alstublieft, maar geen suiker." }, { who: "them", en: "Anything to eat?", nl: "Iets te eten?" }, { who: "you", en: "Yes, I’d like a piece of cake.", nl: "Ja, ik wil graag een stuk cake." }, { who: "them", en: "That will be six pounds, please.", nl: "Dat is zes pond, alstublieft." }, { who: "you", en: "Can I pay by card?", nl: "Kan ik met kaart betalen?" }, { who: "them", en: "Yes, tap your card here.", nl: "Ja, houd uw kaart hier tegenaan." }, { who: "you", en: "Thank you. Can I have the receipt?", nl: "Dank u. Mag ik de bon?" }, { who: "them", en: "Here you go. Have a nice day.", nl: "Alstublieft. Fijne dag." }, { who: "you", en: "Thank you, you too.", nl: "Dank u, u ook." }] },
{ title: "Inchecken in een hotel", scene: "Je komt aan bij een hotel in New York na een lange vlucht. Je hebt online gereserveerd en wilt weten hoe laat het ontbijt is.", lines: [{ who: "them", en: "Hello, welcome to the hotel.", nl: "Hallo, welkom in het hotel." }, { who: "you", en: "Hello, I have a reservation.", nl: "Hallo, ik heb een reservering." }, { who: "them", en: "What is your name, please?", nl: "Wat is uw naam, alstublieft?" }, { who: "you", en: "My name is Van Dijk.", nl: "Mijn naam is Van Dijk." }, { who: "them", en: "Yes, I see your booking here.", nl: "Ja, ik zie uw boeking hier." }, { who: "you", en: "Can I check in now?", nl: "Kan ik nu inchecken?" }, { who: "them", en: "Yes, your room is ready.", nl: "Ja, uw kamer is klaar." }, { who: "you", en: "Is Wi-Fi included?", nl: "Is wifi inbegrepen?" }, { who: "them", en: "Yes, and breakfast is included too.", nl: "Ja, en ontbijt is ook inbegrepen." }, { who: "you", en: "Great. What time is breakfast?", nl: "Geweldig. Hoe laat is het ontbijt?" }, { who: "them", en: "Breakfast is from seven to ten.", nl: "Het ontbijt is van zeven tot tien." }, { who: "you", en: "Thank you very much.", nl: "Hartelijk dank." }] },
{ title: "De weg vragen naar het station", scene: "Je bent in Edinburgh en je telefoon heeft slecht bereik. Je vraagt een voorbijganger hoe je bij het treinstation komt.", lines: [{ who: "you", en: "Excuse me, can you help me?", nl: "Pardon, kunt u mij helpen?" }, { who: "them", en: "Yes, of course.", nl: "Ja, natuurlijk." }, { who: "you", en: "Where is the train station?", nl: "Waar is het treinstation?" }, { who: "them", en: "Go straight ahead and turn left at the corner.", nl: "Ga rechtdoor en sla linksaf bij de hoek." }, { who: "you", en: "Is it far from here?", nl: "Is het ver hiervandaan?" }, { who: "them", en: "No, it’s about ten minutes on foot.", nl: "Nee, het is ongeveer tien minuten te voet." }, { who: "you", en: "Can you show me on the map?", nl: "Kunt u het op de kaart laten zien?" }, { who: "them", en: "Sure, you are here, and the station is here.", nl: "Zeker, u bent hier, en het station is hier." }, { who: "you", en: "Thank you, that helps a lot.", nl: "Dank u, dat helpt enorm." }, { who: "them", en: "No problem. Have a good trip.", nl: "Geen probleem. Goede reis." }, { who: "you", en: "Thanks, have a nice day.", nl: "Bedankt, fijne dag." }] },
{ title: "Eten bestellen in een restaurant", scene: "Je bent in een restaurant in Boston met een vriend. Je hebt een reservering en wilt vragen naar een gerecht zonder noten.", lines: [{ who: "them", en: "Good evening, do you have a reservation?", nl: "Goedenavond, heeft u een reservering?" }, { who: "you", en: "Yes, we have a reservation for two.", nl: "Ja, wij hebben een reservering voor twee." }, { who: "them", en: "What name is it under?", nl: "Op welke naam staat die?" }, { who: "you", en: "It’s under De Vries.", nl: "Die staat op naam van De Vries." }, { who: "them", en: "Perfect, please follow me.", nl: "Perfect, volgt u mij alstublieft." }, { who: "you", en: "Can I see the menu?", nl: "Mag ik het menu zien?" }, { who: "them", en: "Of course, here you are.", nl: "Natuurlijk, alstublieft." }, { who: "you", en: "I’m allergic to nuts. Does this contain nuts?", nl: "Ik ben allergisch voor noten. Bevat dit noten?" }, { who: "them", en: "No, that dish is nut-free.", nl: "Nee, dat gerecht is zonder noten." }, { who: "you", en: "Great, I’ll have that, please.", nl: "Mooi, ik neem dat, alstublieft." }, { who: "them", en: "Excellent choice.", nl: "Uitstekende keuze." }, { who: "you", en: "Thank you.", nl: "Dank u." }] },
{ title: "Kaartjes kopen voor de metro", scene: "Je bent in Londen en wilt met de Underground naar het centrum. Je vraagt bij een medewerker welk kaartje je nodig hebt.", lines: [{ who: "them", en: "Hello, how can I help?", nl: "Hallo, hoe kan ik helpen?" }, { who: "you", en: "I need a ticket to the city center.", nl: "Ik heb een kaartje naar het centrum nodig." }, { who: "them", en: "Are you coming back today?", nl: "Komt u vandaag terug?" }, { who: "you", en: "Yes, I need a return ticket.", nl: "Ja, ik heb een retourkaartje nodig." }, { who: "them", en: "You can use this card for the Underground.", nl: "U kunt deze kaart gebruiken voor de metro." }, { who: "you", en: "Which line do I need?", nl: "Welke lijn heb ik nodig?" }, { who: "them", en: "Take the blue line and change at Green Park.", nl: "Neem de blauwe lijn en stap over bij Green Park." }, { who: "you", en: "Which platform is it?", nl: "Welk perron is het?" }, { who: "them", en: "Platform two, downstairs.", nl: "Perron twee, beneden." }, { who: "you", en: "Thank you for your help.", nl: "Dank u voor uw hulp." }, { who: "them", en: "You’re welcome.", nl: "Graag gedaan." }] },
{ title: "Kleding kopen in een winkel", scene: "Je bent in een kledingwinkel in Dublin. Je zoekt een jas en wilt weten of je hem in een andere maat kunt passen.", lines: [{ who: "them", en: "Hi there, can I help you find anything?", nl: "Hallo, kan ik u ergens mee helpen?" }, { who: "you", en: "Yes, I’m looking for a jacket.", nl: "Ja, ik zoek een jas." }, { who: "them", en: "What size do you need?", nl: "Welke maat heeft u nodig?" }, { who: "you", en: "Medium, please.", nl: "Medium, alstublieft." }, { who: "them", en: "We have this one in medium.", nl: "We hebben deze in medium." }, { who: "you", en: "Can I try it on?", nl: "Mag ik hem passen?" }, { who: "them", en: "Yes, the fitting rooms are over there.", nl: "Ja, de paskamers zijn daar." }, { who: "you", en: "Thank you. It’s a little too small.", nl: "Dank u. Hij is een beetje te klein." }, { who: "them", en: "Would you like to try a large?", nl: "Wilt u een large proberen?" }, { who: "you", en: "Yes, please.", nl: "Ja, graag." }, { who: "them", en: "Here you go.", nl: "Alstublieft." }, { who: "you", en: "This is better. I’ll take it.", nl: "Deze is beter. Ik neem hem." }] },
{ title: "Bij de apotheek", scene: "Je bent in Toronto en hebt hoofdpijn na een drukke reisdag. Je gaat naar een apotheek om advies te vragen.", lines: [{ who: "them", en: "Hello, how can I help you?", nl: "Hallo, hoe kan ik u helpen?" }, { who: "you", en: "Hello, I have a headache.", nl: "Hallo, ik heb hoofdpijn." }, { who: "them", en: "I’m sorry to hear that. Do you need pain medicine?", nl: "Dat spijt me. Heeft u pijnmedicatie nodig?" }, { who: "you", en: "Yes, can you recommend something?", nl: "Ja, kunt u iets aanbevelen?" }, { who: "them", en: "These tablets may help.", nl: "Deze tabletten kunnen helpen." }, { who: "you", en: "Do I need a prescription?", nl: "Heb ik een recept nodig?" }, { who: "them", en: "No, you don’t need a prescription for these.", nl: "Nee, voor deze heeft u geen recept nodig." }, { who: "you", en: "How often should I take them?", nl: "Hoe vaak moet ik ze nemen?" }, { who: "them", en: "Take one tablet every six hours.", nl: "Neem elke zes uur één tablet." }, { who: "you", en: "Thank you. Can I pay by card?", nl: "Dank u. Kan ik met kaart betalen?" }, { who: "them", en: "Yes, of course.", nl: "Ja, natuurlijk." }, { who: "you", en: "Thanks for your help.", nl: "Bedankt voor uw hulp." }] },
{ title: "Smalltalk met een local", scene: "Je zit in een park in Sydney en raakt aan de praat met iemand uit de buurt. Je wilt vriendelijk praten en misschien een lokale tip krijgen.", lines: [{ who: "you", en: "Hi, is this seat available?", nl: "Hoi, is deze plek vrij?" }, { who: "them", en: "Yes, go ahead.", nl: "Ja, ga uw gang." }, { who: "you", en: "Thanks. The weather is beautiful today.", nl: "Bedankt. Het weer is prachtig vandaag." }, { who: "them", en: "It really is. Are you visiting?", nl: "Dat is het zeker. Bent u op bezoek?" }, { who: "you", en: "Yes, I’m from the Netherlands.", nl: "Ja, ik kom uit Nederland." }, { who: "them", en: "Nice. How long are you here?", nl: "Leuk. Hoelang bent u hier?" }, { who: "you", en: "I’m here for a few days.", nl: "Ik ben hier een paar dagen." }, { who: "them", en: "You should visit the harbor.", nl: "U zou de haven moeten bezoeken." }, { who: "you", en: "That sounds interesting. Is it far from here?", nl: "Dat klinkt interessant. Is het ver hiervandaan?" }, { who: "them", en: "No, you can take the bus.", nl: "Nee, u kunt de bus nemen." }, { who: "you", en: "Great, thank you for the tip.", nl: "Geweldig, bedankt voor de tip." }, { who: "them", en: "You’re welcome. Enjoy Sydney.", nl: "Graag gedaan. Geniet van Sydney." }] }
];
